def resolve_rate(model, rate_card, overrides):
    """Resolve the effective per-token rate for a model."""
    if model in overrides:
        base = overrides[model].get('base')
        cached = overrides[model].get('cached')
        if base is not None:
            return base, (cached if cached is not None else base)
    row = rate_card.get(model)
    if row is None:
        raise KeyError(f'no rate for {model}')
    return row.base_input_rate, row.cached_input_rate


def blended(base, cached, hit_ratio):
    h = min(max(hit_ratio, 0.0), 1.0)
    return cached * h + base * (1.0 - h)
